{
  "name": "Layout Forge",
  "description": "A powerful layout editor that allows you to overlay images and iframes on a background, with full move and resize capabilities, local persistence, and import/export functionality."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ContentType {
  IMAGE = 'IMAGE',
  IFRAME = 'IFRAME',
}

export interface OverlayItem {
  id: string;
  type: ContentType;
  src: string; // URL or Data URI
  x: number;
  y: number;
  width: number;
  height: number;
  zIndex: number;
  opacity: number;
}

export interface AppState {
  backgroundType: ContentType;
  backgroundSrc: string;
  overlays: OverlayItem[];
}

export const DEFAULT_WIDTH = 200;
export const DEFAULT_HEIGHT = 150;

export const generateId = (): string => {
  return Math.random().toString(36).substring(2, 9);
};

export const fileToDataUri = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        resolve(e.target.result as string);
      } else {
        reject(new Error("Failed to read file"));
      }
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const downloadJson = (data: any, filename: string) => {
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { OverlayItem, ContentType } from '../types';
import { Trash2, GripHorizontal, Move, Maximize2 } from 'lucide-react';

interface OverlayElementProps {
  item: OverlayItem;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onUpdate: (id: string, updates: Partial<OverlayItem>) => void;
  onDelete: (id: string) => void;
  scale: number; // For zoom support if needed, defaulting to 1 usually
}

const HANDLE_SIZE = 12;

export const OverlayElement: React.FC<OverlayElementProps> = ({
  item,
  isSelected,
  onSelect,
  onUpdate,
  onDelete,
  scale = 1
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [resizeDir, setResizeDir] = useState<string | null>(null);

  // Refs for current values during drag (avoiding re-renders for performance)
  const elementRef = useRef<HTMLDivElement>(null);
  const startPos = useRef({ x: 0, y: 0 });
  const startDims = useRef({ x: 0, y: 0, w: 0, h: 0 });

  const handleMouseDown = (e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(item.id);

    // Only start drag if left click
    if (e.button !== 0) return;

    setIsDragging(true);
    startPos.current = { x: e.clientX, y: e.clientY };
    startDims.current = { x: item.x, y: item.y, w: item.width, h: item.height };

    // Add global class to body to disable iframes
    document.body.classList.add('dragging-active');
  };

  const handleResizeStart = (e: React.MouseEvent, dir: string) => {
    e.stopPropagation();
    e.preventDefault(); // Prevent text selection
    onSelect(item.id);

    setIsResizing(true);
    setResizeDir(dir);
    startPos.current = { x: e.clientX, y: e.clientY };
    startDims.current = { x: item.x, y: item.y, w: item.width, h: item.height };

    document.body.classList.add('dragging-active');
  };

  const onWindowMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging && !isResizing) return;

    const dx = (e.clientX - startPos.current.x) / scale;
    const dy = (e.clientY - startPos.current.y) / scale;

    if (isDragging) {
      onUpdate(item.id, {
        x: startDims.current.x + dx,
        y: startDims.current.y + dy
      });
    } else if (isResizing && resizeDir) {
      let newX = startDims.current.x;
      let newY = startDims.current.y;
      let newW = startDims.current.w;
      let newH = startDims.current.h;

      if (resizeDir.includes('e')) newW = Math.max(50, startDims.current.w + dx);
      if (resizeDir.includes('s')) newH = Math.max(50, startDims.current.h + dy);
      if (resizeDir.includes('w')) {
        const proposedW = startDims.current.w - dx;
        if (proposedW > 50) {
          newX = startDims.current.x + dx;
          newW = proposedW;
        }
      }
      if (resizeDir.includes('n')) {
        const proposedH = startDims.current.h - dy;
        if (proposedH > 50) {
          newY = startDims.current.y + dy;
          newH = proposedH;
        }
      }

      onUpdate(item.id, { x: newX, y: newY, width: newW, height: newH });
    }
  }, [isDragging, isResizing, resizeDir, item.id, onUpdate, scale]);

  const onWindowMouseUp = useCallback(() => {
    if (isDragging || isResizing) {
      setIsDragging(false);
      setIsResizing(false);
      setResizeDir(null);
      document.body.classList.remove('dragging-active');
    }
  }, [isDragging, isResizing]);

  useEffect(() => {
    if (isDragging || isResizing) {
      window.addEventListener('mousemove', onWindowMouseMove);
      window.addEventListener('mouseup', onWindowMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', onWindowMouseMove);
      window.removeEventListener('mouseup', onWindowMouseUp);
    };
  }, [isDragging, isResizing, onWindowMouseMove, onWindowMouseUp]);

  // Handle z-index simple increment on click (optional UX choice, handled by selection in parent usually)

  const borderClass = isSelected ? 'border-2 border-blue-500 shadow-[0_0_0_2px_rgba(59,130,246,0.5)]' : 'border border-transparent hover:border-slate-500/50';

  return (
    <div
      ref={elementRef}
      className={`absolute select-none group ${borderClass} transition-shadow duration-150`}
      style={{
        transform: `translate(${item.x}px, ${item.y}px)`,
        width: item.width,
        height: item.height,
        zIndex: item.zIndex,
      }}
      onMouseDown={handleMouseDown}
    >
      {/* Content */}
      <div className="w-full h-full overflow-hidden bg-slate-800/50 relative">
        {item.type === ContentType.IMAGE ? (
          <img 
            src={item.src} 
            alt="overlay" 
            className="w-full h-full object-cover pointer-events-none" 
            style={{ opacity: item.opacity }}
          />
        ) : (
          <>
            <div className="absolute inset-0 z-10 bg-transparent" /> {/* Click shield for iframe */}
            <iframe 
              src={item.src} 
              className="w-full h-full pointer-events-none" 
              title={`frame-${item.id}`}
              style={{ opacity: item.opacity }}
            />
          </>
        )}
      </div>

      {/* Controls Overlay (Visible on Hover or Select) */}
      {(isSelected) && (
        <>
          {/* Resize Handles */}
          <div className="absolute -top-1.5 -left-1.5 w-3 h-3 bg-blue-500 cursor-nw-resize rounded-full border border-white z-50" onMouseDown={(e) => handleResizeStart(e, 'nw')} />
          <div className="absolute -top-1.5 -right-1.5 w-3 h-3 bg-blue-500 cursor-ne-resize rounded-full border border-white z-50" onMouseDown={(e) => handleResizeStart(e, 'ne')} />
          <div className="absolute -bottom-1.5 -left-1.5 w-3 h-3 bg-blue-500 cursor-sw-resize rounded-full border border-white z-50" onMouseDown={(e) => handleResizeStart(e, 'sw')} />
          <div className="absolute -bottom-1.5 -right-1.5 w-3 h-3 bg-blue-500 cursor-se-resize rounded-full border border-white z-50" onMouseDown={(e) => handleResizeStart(e, 'se')} />

          {/* Delete Button */}
          <button
            className="absolute -top-10 right-0 bg-red-500 text-white p-1.5 rounded-md shadow-sm hover:bg-red-600 transition-colors z-50"
            onMouseDown={(e) => { e.stopPropagation(); onDelete(item.id); }}
            title="Remove Overlay"
          >
            <Trash2 size={16} />
          </button>

          {/* Opacity Control (Simple slider above) */}
          <div className="absolute -top-10 right-10 bg-slate-800 p-1 rounded-md shadow-sm flex items-center gap-2 border border-slate-700 z-50" onMouseDown={e => e.stopPropagation()}>
             <span className="text-xs text-slate-400 px-1">Opacity</span>
             <input 
               type="range" 
               min="0.1" 
               max="1" 
               step="0.1" 
               value={item.opacity} 
               onChange={(e) => onUpdate(item.id, { opacity: parseFloat(e.target.value) })}
               className="w-16 h-1 bg-slate-600 rounded-lg appearance-none cursor-pointer"
             />
          </div>
        </>
      )}
    </div>
  );
};

import React, { useRef } from 'react';
import { Download, Upload, Plus, Image as ImageIcon, Globe, Monitor, Settings, Trash } from 'lucide-react';
import { fileToDataUri } from '../utils/helpers';
import { ContentType } from '../types';

interface ToolbarProps {
  onAddOverlay: (type: ContentType, src: string) => void;
  onSetBackground: (type: ContentType, src: string) => void;
  onSave: () => void;
  onLoad: (file: File) => void;
  onClear: () => void;
}

export const Toolbar: React.FC<ToolbarProps> = ({
  onAddOverlay,
  onSetBackground,
  onSave,
  onLoad,
  onClear
}) => {
  const bgInputRef = useRef<HTMLInputElement>(null);
  const overlayInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  const handleBgUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const uri = await fileToDataUri(e.target.files[0]);
      onSetBackground(ContentType.IMAGE, uri);
    }
    // Reset
    if (bgInputRef.current) bgInputRef.current.value = '';
  };

  const handleOverlayUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const uri = await fileToDataUri(e.target.files[i]);
        onAddOverlay(ContentType.IMAGE, uri);
      }
    }
    if (overlayInputRef.current) overlayInputRef.current.value = '';
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      onLoad(e.target.files[0]);
    }
    if (importInputRef.current) importInputRef.current.value = '';
  };

  const promptForUrl = (callback: (src: string) => void) => {
    const url = prompt("Enter the URL (e.g., https://example.com)");
    if (url) callback(url);
  };

  return (
    <div className="h-16 bg-slate-800 border-b border-slate-700 flex items-center px-4 justify-between select-none shadow-md z-50 relative">
      <div className="flex items-center gap-4">
        <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2">
          <Settings className="text-blue-400" /> Layout Forge
        </h1>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        {/* Background Controls */}
        <div className="flex items-center gap-2">
          <span className="text-xs uppercase font-semibold text-slate-500 tracking-wider">Background</span>
          <button 
            onClick={() => bgInputRef.current?.click()}
            className="btn-secondary"
            title="Set Background Image"
          >
            <ImageIcon size={18} />
          </button>
          <button 
             onClick={() => promptForUrl((url) => onSetBackground(ContentType.IFRAME, url))}
             className="btn-secondary"
             title="Set Background URL"
          >
            <Globe size={18} />
          </button>
          <input ref={bgInputRef} type="file" accept="image/*" className="hidden" onChange={handleBgUpload} />
        </div>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        {/* Overlay Controls */}
        <div className="flex items-center gap-2">
           <span className="text-xs uppercase font-semibold text-slate-500 tracking-wider">Overlays</span>
          <button 
            onClick={() => overlayInputRef.current?.click()}
            className="btn-primary"
          >
            <Plus size={18} /> <ImageIcon size={18} />
          </button>
           <button 
            onClick={() => promptForUrl((url) => onAddOverlay(ContentType.IFRAME, url))}
            className="btn-primary"
            title="Add Website Overlay"
          >
            <Plus size={18} /> <Monitor size={18} />
          </button>
          <input ref={overlayInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleOverlayUpload} />
        </div>
      </div>

      <div className="flex items-center gap-3">
        <button 
          onClick={onClear}
          className="text-red-400 hover:text-red-300 hover:bg-red-900/20 px-3 py-2 rounded-md transition-colors flex items-center gap-2"
        >
          <Trash size={16} /> <span className="hidden sm:inline">Clear</span>
        </button>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        <button 
          onClick={() => importInputRef.current?.click()}
          className="text-slate-300 hover:text-white hover:bg-slate-700 px-3 py-2 rounded-md transition-colors flex items-center gap-2"
        >
          <Upload size={16} /> <span className="hidden sm:inline">Import</span>
        </button>
        <input ref={importInputRef} type="file" accept=".json" className="hidden" onChange={handleImport} />

        <button 
          onClick={onSave}
          className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-md transition-colors shadow-lg flex items-center gap-2 font-medium"
        >
          <Download size={16} /> Export
        </button>
      </div>

      {/* Basic styles for buttons injected via style tag for simplicity in this constrained output, or just utility classes */}
      <style>{`
        .btn-primary {
          @apply flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-slate-100 px-3 py-2 rounded-md transition-all active:scale-95 border border-slate-600;
        }
        .btn-secondary {
          @apply flex items-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-300 px-3 py-2 rounded-md transition-all active:scale-95 border border-slate-700;
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Toolbar } from './components/Toolbar';
import { OverlayElement } from './components/OverlayElement';
import { OverlayItem, AppState, ContentType, DEFAULT_WIDTH, DEFAULT_HEIGHT } from './types';
import { generateId, downloadJson } from './utils/helpers';

// Helper to check for existing saved state
const STORAGE_KEY = 'layout_forge_state';

const App: React.FC = () => {
  const [background, setBackground] = useState<{ type: ContentType, src: string }>({
    type: ContentType.IMAGE,
    src: ''
  });
  const [overlays, setOverlays] = useState<OverlayItem[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // --- Persistence ---

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed: AppState = JSON.parse(saved);
        setBackground({ type: parsed.backgroundType, src: parsed.backgroundSrc });
        setOverlays(parsed.overlays);
      } catch (e) {
        console.error("Failed to load state", e);
      }
    }
  }, []);

  // Save to local storage whenever state changes
  useEffect(() => {
    const state: AppState = {
      backgroundType: background.type,
      backgroundSrc: background.src,
      overlays
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [background, overlays]);

  // --- Actions ---

  const handleAddOverlay = (type: ContentType, src: string) => {
    const newOverlay: OverlayItem = {
      id: generateId(),
      type,
      src,
      x: 100 + (overlays.length * 20), // Cascade effect
      y: 100 + (overlays.length * 20),
      width: DEFAULT_WIDTH,
      height: DEFAULT_HEIGHT,
      zIndex: overlays.length + 1,
      opacity: 1,
    };
    setOverlays(prev => [...prev, newOverlay]);
    setSelectedId(newOverlay.id);
  };

  const handleSetBackground = (type: ContentType, src: string) => {
    setBackground({ type, src });
  };

  const handleUpdateOverlay = useCallback((id: string, updates: Partial<OverlayItem>) => {
    setOverlays(prev => prev.map(item => 
      item.id === id ? { ...item, ...updates } : item
    ));
  }, []);

  const handleDeleteOverlay = (id: string) => {
    setOverlays(prev => prev.filter(item => item.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleClear = () => {
    if (window.confirm("Are you sure you want to clear the entire layout?")) {
      setOverlays([]);
      setBackground({ type: ContentType.IMAGE, src: '' });
      setSelectedId(null);
    }
  };

  // --- Import / Export ---

  const handleExport = () => {
    const state: AppState = {
      backgroundType: background.type,
      backgroundSrc: background.src,
      overlays
    };
    downloadJson(state, `layout-forge-${new Date().toISOString().slice(0, 10)}.json`);
  };

  const handleImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const parsed: AppState = JSON.parse(e.target?.result as string);
        // Validate basic structure
        if (parsed.overlays && Array.isArray(parsed.overlays)) {
          setBackground({ 
            type: parsed.backgroundType || ContentType.IMAGE, 
            src: parsed.backgroundSrc || '' 
          });
          setOverlays(parsed.overlays);
        } else {
          alert("Invalid file format");
        }
      } catch (err) {
        alert("Failed to parse file");
      }
    };
    reader.readAsText(file);
  };

  const handleBackgroundClick = () => {
    setSelectedId(null);
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-900 text-slate-100 overflow-hidden">
      <Toolbar 
        onAddOverlay={handleAddOverlay}
        onSetBackground={handleSetBackground}
        onSave={handleExport}
        onLoad={handleImport}
        onClear={handleClear}
      />

      {/* Workspace Area */}
      <div 
        className="flex-1 relative overflow-auto bg-slate-900/50"
        onMouseDown={handleBackgroundClick} // Deselect when clicking empty space
      >
        {/* Background Layer */}
        <div className="absolute inset-0 min-w-full min-h-full flex items-center justify-center pointer-events-none z-0">
          {background.src ? (
            background.type === ContentType.IMAGE ? (
              <img 
                src={background.src} 
                alt="Background" 
                className="w-full h-full object-cover opacity-100" // You might want 'contain' or 'cover' depending on user pref, defaulting to cover for full bg feel
              />
            ) : (
              <iframe 
                src={background.src} 
                className="w-full h-full border-none pointer-events-auto" // Background iframe needs events if it's the base
                title="Background Page"
              />
            )
          ) : (
             <div className="text-slate-600 flex flex-col items-center">
               <div className="text-6xl font-black opacity-20 select-none">EMPTY</div>
               <p className="opacity-40 mt-4">Set a background or add overlays to start</p>
             </div>
          )}
        </div>

        {/* Overlay Layer - Renders on top of background */}
        <div className="absolute inset-0 w-full h-full overflow-hidden z-10 pointer-events-none">
          {/* We use pointer-events-none on container so clicks pass through to background if not hitting an item, 
              but OverlayElement itself has pointer-events-auto implicitly via div */}
          {overlays.map(item => (
            <div key={item.id} className="pointer-events-auto">
              <OverlayElement
                item={item}
                isSelected={selectedId === item.id}
                onSelect={setSelectedId}
                onUpdate={handleUpdateOverlay}
                onDelete={handleDeleteOverlay}
                scale={1}
              />
            </div>
          ))}
        </div>
      </div>

      {/* Footer Info */}
      <div className="h-6 bg-slate-950 text-slate-500 text-xs flex items-center px-4 justify-between border-t border-slate-800 z-50">
        <span>{overlays.length} item(s)</span>
        <span>{background.src ? 'Background Active' : 'No Background'}</span>
      </div>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { Download, Upload, Plus, Image as ImageIcon, Globe, Monitor, Settings, Trash } from 'lucide-react';
import { fileToDataUri } from '../utils/helpers';
import { ContentType } from '../types';

interface ToolbarProps {
  onAddOverlay: (type: ContentType, src: string) => void;
  onSetBackground: (type: ContentType, src: string) => void;
  onSave: () => void;
  onLoad: (file: File) => void;
  onClear: () => void;
}

const BTN_PRIMARY = "flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-slate-100 px-3 py-2 rounded-md transition-all active:scale-95 border border-slate-600 cursor-pointer";
const BTN_SECONDARY = "flex items-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-300 px-3 py-2 rounded-md transition-all active:scale-95 border border-slate-700 cursor-pointer";

export const Toolbar: React.FC<ToolbarProps> = ({
  onAddOverlay,
  onSetBackground,
  onSave,
  onLoad,
  onClear
}) => {
  const bgInputRef = useRef<HTMLInputElement>(null);
  const overlayInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  const handleBgUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const uri = await fileToDataUri(e.target.files[0]);
      onSetBackground(ContentType.IMAGE, uri);
    }
    // Reset
    if (bgInputRef.current) bgInputRef.current.value = '';
  };

  const handleOverlayUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const uri = await fileToDataUri(e.target.files[i]);
        onAddOverlay(ContentType.IMAGE, uri);
      }
    }
    if (overlayInputRef.current) overlayInputRef.current.value = '';
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      onLoad(e.target.files[0]);
    }
    if (importInputRef.current) importInputRef.current.value = '';
  };

  const promptForUrl = (callback: (src: string) => void) => {
    let url = prompt("Enter the URL (e.g., wikipedia.org)");
    if (!url) return;

    url = url.trim();
    if (!/^https?:\/\//i.test(url)) {
      url = 'https://' + url;
    }

    callback(url);
  };

  return (
    <div className="h-16 bg-slate-800 border-b border-slate-700 flex items-center px-4 justify-between select-none shadow-md z-50 relative">
      <div className="flex items-center gap-4">
        <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2">
          <Settings className="text-blue-400" /> Layout Forge
        </h1>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        {/* Background Controls */}
        <div className="flex items-center gap-2">
          <span className="text-xs uppercase font-semibold text-slate-500 tracking-wider">Background</span>
          <button 
            onClick={() => bgInputRef.current?.click()}
            className={BTN_SECONDARY}
            title="Set Background Image"
          >
            <ImageIcon size={18} />
          </button>
          <button 
             onClick={() => promptForUrl((url) => onSetBackground(ContentType.IFRAME, url))}
             className={BTN_SECONDARY}
             title="Set Background URL"
          >
            <Globe size={18} />
          </button>
          <input ref={bgInputRef} type="file" accept="image/*" className="hidden" onChange={handleBgUpload} />
