    setSelectedId(null);
  };

  // Construct valid YouTube URL with origin to prevent Error 153/101
  const getYoutubeEmbedUrl = (id: string) => {
    // Use URLSearchParams for cleaner parameter handling
    const params = new URLSearchParams({
        autoplay: '1',
        mute: '1',
        controls: '0',
        loop: '1',
        playlist: id, // Required for looping single video
        playsinline: '1',
        rel: '0',
        iv_load_policy: '3',
        disablekb: '1',
