      onSetBackground(ContentType.IMAGE, uri);
    }
    // Reset
    if (bgInputRef.current) bgInputRef.current.value = '';
  };

  const handleOverlayUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const uri = await fileToDataUri(e.target.files[i]);
        onAddOverlay(ContentType.IMAGE, uri);
      }
    }
    if (overlayInputRef.current) overlayInputRef.current.value = '';
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      onLoad(e.target.files[0]);
    }
    if (importInputRef.current) importInputRef.current.value = '';
  };

  const getBackgroundUrlDefault = () => {
    if (currentBackground.type === ContentType.YOUTUBE) {
      return `https://www.youtube.com/watch?v=${currentBackground.src}`;
    }
    if (currentBackground.type === ContentType.IFRAME || currentBackground.type === ContentType.IMAGE) {
      // Don't pre-fill if it's a massive data URI
      if (currentBackground.src.startsWith('data:')) return '';
      return currentBackground.src;
    }
    return '';
  };

  return (
    <div className="h-16 bg-slate-800 border-b border-slate-700 flex items-center px-4 justify-between select-none shadow-md z-50 relative">
      <div className="flex items-center gap-4">
        <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2">
          <Settings className="text-blue-400" /> Layout Forge
        </h1>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        {/* Background Controls */}
        <div className="flex items-center gap-2">
          <span className="text-xs uppercase font-semibold text-slate-500 tracking-wider">Background</span>
          <button 
            onClick={() => bgInputRef.current?.click()}
            className={BTN_SECONDARY}
            title="Set Background Image"
          >
            <ImageIcon size={18} />
          </button>
          <button 
            onClick={() => onOpenUrlModal(
              "Set Background Web Page", 
              (url) => onSetBackground(ContentType.IFRAME, url),
              getBackgroundUrlDefault()
            )}
            className={BTN_SECONDARY}
            title="Set Background URL"
          >
            <Globe size={18} />
          </button>
          <input ref={bgInputRef} type="file" accept="image/*" className="hidden" onChange={handleBgUpload} />
        </div>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        {/* Overlay Controls */}
        <div className="flex items-center gap-2">
          <span className="text-xs uppercase font-semibold text-slate-500 tracking-wider">Overlays</span>
          <button 
            onClick={() => overlayInputRef.current?.click()}
            className={BTN_PRIMARY}
            title="Add Image Overlay"
          >
            <Plus size={18} /> <ImageIcon size={18} />
          </button>
          <button 
            onClick={() => onOpenUrlModal("Add Web Image Overlay", (url) => onAddOverlay(ContentType.IMAGE, url))}
            className={BTN_PRIMARY}
            title="Add Web Image Overlay"
          >
             <Plus size={18} /> <Link size={18} />
          </button>
          <button 
            onClick={() => onOpenUrlModal("Add Web Page Overlay", (url) => onAddOverlay(ContentType.IFRAME, url))}
            className={BTN_PRIMARY}
            title="Add Website Overlay"
          >
            <Plus size={18} /> <Monitor size={18} />
          </button>
          <input ref={overlayInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleOverlayUpload} />
        </div>
      </div>

      <div className="flex items-center gap-3">
        <button 
          onClick={onToggleFullScreen}
          className="text-slate-400 hover:text-white hover:bg-slate-700/50 p-2 rounded-md transition-colors flex items-center gap-2"
          title="Toggle Full Screen"
        >
          {isFullScreen ? <Minimize size={18} /> : <Maximize size={18} />}
        </button>
        <button 
          onClick={onHideUI}
          className="text-slate-400 hover:text-white hover:bg-slate-700/50 p-2 rounded-md transition-colors flex items-center gap-2"
          title="Hide Toolbar & Status"
        >
          <EyeOff size={18} />
        </button>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        <button 
          onClick={onClear}
          className="text-red-400 hover:text-red-300 hover:bg-red-900/20 px-3 py-2 rounded-md transition-colors flex items-center gap-2 cursor-pointer"
        >
          <Trash size={16} /> <span className="hidden sm:inline">Clear</span>
        </button>

        <button 
          onClick={() => importInputRef.current?.click()}
          className="text-slate-300 hover:text-white hover:bg-slate-700 px-3 py-2 rounded-md transition-colors flex items-center gap-2 cursor-pointer"
        >
          <Upload size={16} /> <span className="hidden sm:inline">Import</span>
        </button>
        <input ref={importInputRef} type="file" accept=".json" className="hidden" onChange={handleImport} />

        <button 
          onClick={onSave}
          className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-md transition-colors shadow-lg flex items-center gap-2 font-medium cursor-pointer"
        >
          <Download size={16} /> Export
        </button>

        <button 
          onClick={onOpenConfigModal}
          className="text-slate-300 hover:text-white hover:bg-slate-700 px-3 py-2 rounded-md transition-colors flex items-center gap-2 cursor-pointer"
          title="View/Edit Configuration JSON"
        >
          <FileJson size={16} />
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Toolbar } from './components/Toolbar';
import { OverlayElement } from './components/OverlayElement';
import { OverlayItem, AppState, ContentType, DEFAULT_WIDTH, DEFAULT_HEIGHT } from './types';
import { generateId, downloadJson, getYouTubeId, getYouTubeEmbedUrl, isImageUrl } from './utils/helpers';
import { Eye, X, Maximize, Minimize, Clipboard, Check } from 'lucide-react';

// Helper to check for existing saved state
const STORAGE_KEY = 'layout_forge_state';

const App: React.FC = () => {
  const [background, setBackground] = useState<{ type: ContentType, src: string }>({
    type: ContentType.IMAGE,
    src: ''
  });
  const [overlays, setOverlays] = useState<OverlayItem[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [showUI, setShowUI] = useState(true);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Modal State
  const [modalConfig, setModalConfig] = useState<{
    isOpen: boolean;
    title: string;
    defaultValue?: string;
    callback: (url: string) => void;
  } | null>(null);
  const [urlInput, setUrlInput] = useState('');

  // Config JSON Modal
  const [configModalOpen, setConfigModalOpen] = useState(false);
  const [configJson, setConfigJson] = useState('');
  const [copyFeedback, setCopyFeedback] = useState(false);

  // --- Persistence & Initialization ---

  // Load from URL or local storage on mount
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const configParam = params.get('config');

    if (configParam) {
      try {
        const parsed: AppState = JSON.parse(decodeURIComponent(configParam));
        if (parsed) {
          setBackground({ 
            type: parsed.backgroundType || ContentType.IMAGE, 
            src: parsed.backgroundSrc || '' 
          });
          setOverlays(parsed.overlays || []);
          // Clear URL to avoid state lock, or keep it? 
          // Better to clean it so refreshing doesn't overwrite local changes immediately if not intended.
          // For now, we leave it, but user can clear it.
          window.history.replaceState({}, document.title, window.location.pathname);
          return;
        }
      } catch (e) {
        console.error("Failed to parse config from URL", e);
      }
    }

    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed: AppState = JSON.parse(saved);
        setBackground({ type: parsed.backgroundType, src: parsed.backgroundSrc });
        setOverlays(parsed.overlays);
      } catch (e) {
        console.error("Failed to load state", e);
      }
    }
  }, []);

  // Save to local storage whenever state changes
  useEffect(() => {
    const state: AppState = {
      backgroundType: background.type,
      backgroundSrc: background.src,
      overlays
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [background, overlays]);

  // Handle Full Screen Change Events
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  // --- Actions ---

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  const handleAddOverlay = (type: ContentType, src: string) => {
    let finalType = type;
    let finalSrc = src;

    // Check if the source is actually a YouTube link
    const ytId = getYouTubeId(src);
    if (ytId) {
      finalType = ContentType.YOUTUBE;
      finalSrc = ytId;
    } else if (isImageUrl(src)) {
      // Auto-detect image
      finalType = ContentType.IMAGE;
    }

    // Determine reasonable default dimensions based on content type
    const width = finalType === ContentType.IMAGE ? DEFAULT_WIDTH : 600;
    const height = finalType === ContentType.IMAGE ? DEFAULT_HEIGHT : 450;

    // Calculate max z-index
    const maxZ = overlays.length > 0 ? Math.max(...overlays.map(o => o.zIndex)) : 0;

    const newOverlay: OverlayItem = {
      id: generateId(),
      type: finalType,
      src: finalSrc,
      x: 100 + (overlays.length * 20), // Cascade effect
      y: 100 + (overlays.length * 20),
      width,
      height,
      zIndex: maxZ + 1,
      opacity: 1,
    };
    setOverlays(prev => [...prev, newOverlay]);
    setSelectedId(newOverlay.id);
  };

  const handleSetBackground = (type: ContentType, src: string) => {
    // Check for YouTube URL
    const ytId = getYouTubeId(src);
    if (ytId) {
      setBackground({ type: ContentType.YOUTUBE, src: ytId });
    } else if (isImageUrl(src)) {
      setBackground({ type: ContentType.IMAGE, src });
    } else {
      setBackground({ type, src });
    }
  };

  const handleUpdateOverlay = useCallback((id: string, updates: Partial<OverlayItem>) => {
    setOverlays(prev => prev.map(item => 
      item.id === id ? { ...item, ...updates } : item
    ));
  }, []);

  const handleDeleteOverlay = (id: string) => {
    setOverlays(prev => prev.filter(item => item.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleEditOverlay = (id: string, currentSrc: string) => {
    const item = overlays.find(o => o.id === id);
    const title = item?.type === ContentType.IMAGE ? "Edit Image Source" : "Edit URL";

    // For YouTube items, reconstruct a watch URL for editing if possible, or just pass the ID
    let displayValue = currentSrc;
    if (item?.type === ContentType.YOUTUBE) {
        displayValue = `https://www.youtube.com/watch?v=${currentSrc}`;
    }

    openUrlModal(title, (newUrl) => {
       // Check if new URL is YouTube
       const ytId = getYouTubeId(newUrl);
       if (ytId) {
         handleUpdateOverlay(id, { type: ContentType.YOUTUBE, src: ytId });
       } else if (isImageUrl(newUrl)) {
         handleUpdateOverlay(id, { type: ContentType.IMAGE, src: newUrl });
       } else {
         handleUpdateOverlay(id, { src: newUrl });
       }
    }, displayValue);
  };

  // Reorder Logic
  const handleLayerAction = (id: string, action: 'front' | 'back' | 'forward' | 'backward') => {
    setOverlays(prev => {
      // 1. Create a copy and sort by current zIndex to establish order
      const items = [...prev].sort((a, b) => a.zIndex - b.zIndex);

      const idx = items.findIndex(i => i.id === id);
      if (idx === -1) return prev;

      const item = items[idx];
      items.splice(idx, 1); // Remove item from current position

      // 2. Insert at new position
      if (action === 'front') {
        items.push(item);
      } else if (action === 'back') {
        items.unshift(item);
      } else if (action === 'forward') {
        // Swap with next if possible
        const newIdx = Math.min(items.length, idx + 1);
        items.splice(newIdx, 0, item);
      } else if (action === 'backward') {
        // Swap with prev if possible
        const newIdx = Math.max(0, idx - 1);
        items.splice(newIdx, 0, item);
      }

      // 3. Re-assign zIndices sequentially to normalize
      return items.map((itm, index) => ({
        ...itm,
        zIndex: index + 1
      }));
    });
  };

  const handleClear = () => {
    if (window.confirm("Are you sure you want to clear the entire layout?")) {
      setOverlays([]);
      setBackground({ type: ContentType.IMAGE, src: '' });
      setSelectedId(null);
    }
  };

  // --- Modal Logic ---

  const openUrlModal = (title: string, callback: (src: string) => void, defaultValue = '') => {
    setUrlInput(defaultValue);
    setModalConfig({ isOpen: true, title, defaultValue, callback });
  };

  const handleModalSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!modalConfig || !urlInput.trim()) return;

    let url = urlInput.trim();
    if (!/^https?:\/\//i.test(url) && !url.startsWith('data:')) {
      url = 'https://' + url;
    }

    modalConfig.callback(url);
    setModalConfig(null);
  };

  // --- Import / Export ---

  const handleExport = () => {
    const state: AppState = {
      backgroundType: background.type,
      backgroundSrc: background.src,
      overlays
    };
    downloadJson(state, `layout-forge-${new Date().toISOString().slice(0, 10)}.json`);
  };

  const handleImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const parsed: AppState = JSON.parse(e.target?.result as string);
        if (parsed.overlays && Array.isArray(parsed.overlays)) {
          setBackground({ 
            type: parsed.backgroundType || ContentType.IMAGE, 
            src: parsed.backgroundSrc || '' 
          });
          setOverlays(parsed.overlays);
        } else {
          alert("Invalid file format");
        }
      } catch (err) {
        alert("Failed to parse file");
      }
    };
    reader.readAsText(file);
  };

  // --- Config Modal Logic ---

  const handleOpenConfig = () => {
    const state: AppState = {
      backgroundType: background.type,
      backgroundSrc: background.src,
      overlays
    };
    setConfigJson(JSON.stringify(state, null, 2));
    setConfigModalOpen(true);
    setCopyFeedback(false);
  };

  const handleApplyConfig = () => {
    try {
      const parsed: AppState = JSON.parse(configJson);
      if (parsed) {
        setBackground({ 
          type: parsed.backgroundType || ContentType.IMAGE, 
          src: parsed.backgroundSrc || '' 
        });
        setOverlays(parsed.overlays || []);
        setConfigModalOpen(false);
      }
    } catch (e) {
      alert("Invalid JSON configuration");
    }
  };

  const handleCopyConfig = () => {
    navigator.clipboard.writeText(configJson).then(() => {
      setCopyFeedback(true);
      setTimeout(() => setCopyFeedback(false), 2000);
    });
  };

  const handleBackgroundClick = () => {
    setSelectedId(null);
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-900 text-slate-100 overflow-hidden relative">

      {/* Floating Toggle Buttons (Visible when UI is hidden) */}
      {!showUI && (
        <div className="absolute top-4 right-4 z-[9998] flex gap-2">
           <button 
            onClick={toggleFullScreen}
            className="bg-slate-800/80 hover:bg-slate-700 text-white p-2 rounded-full shadow-lg backdrop-blur-sm transition-all opacity-10 hover:opacity-100 duration-300"
            title="Toggle Full Screen"
          >
            {isFullScreen ? <Minimize size={20} /> : <Maximize size={20} />}
          </button>
          <button 
            onClick={() => setShowUI(true)}
            className="bg-slate-800/80 hover:bg-slate-700 text-white p-2 rounded-full shadow-lg backdrop-blur-sm transition-all opacity-10 hover:opacity-100 duration-300"
            title="Show Interface"
          >
            <Eye size={20} />
          </button>
        </div>
      )}

      {showUI && (
        <Toolbar 
          currentBackground={background}
          onAddOverlay={handleAddOverlay}
          onSetBackground={handleSetBackground}
          onSave={handleExport}
          onLoad={handleImport}
          onClear={handleClear}
          onOpenUrlModal={openUrlModal}
          onOpenConfigModal={handleOpenConfig}
          onHideUI={() => setShowUI(false)}
          onToggleFullScreen={toggleFullScreen}
          isFullScreen={isFullScreen}
        />
      )}

      {/* Workspace Area */}
      <div 
        className="flex-1 relative overflow-auto bg-slate-900/50"
        onMouseDown={handleBackgroundClick} // Deselect when clicking empty space
      >
        {/* Background Layer */}
        <div className="absolute inset-0 min-w-full min-h-full flex items-center justify-center pointer-events-none z-0">
          {background.src ? (
            background.type === ContentType.IMAGE ? (
              <div 
                className="w-full h-full bg-no-repeat bg-center bg-cover opacity-100"
                style={{ backgroundImage: `url("${background.src}")` }}
              />
            ) : background.type === ContentType.YOUTUBE ? (
              <div className="absolute inset-0 w-full h-full overflow-hidden">
                 <iframe
                   src={getYouTubeEmbedUrl(background.src)}
                   className="w-full h-full pointer-events-none"
                   allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
                   referrerPolicy="strict-origin-when-cross-origin"
                   title="Background Video"
                 />
                 <div className="absolute inset-0 z-10 bg-transparent" />
              </div>
            ) : (
              <iframe 
                src={background.src} 
                className="w-full h-full border-none pointer-events-auto" 
                title="Background Page"
              />
            )
          ) : (
             <div className="text-slate-600 flex flex-col items-center">
               <div className="text-6xl font-black opacity-20 select-none">EMPTY</div>
               <p className="opacity-40 mt-4">Set a background or add overlays to start</p>
             </div>
          )}
        </div>

        {/* Overlay Layer - Renders on top of background */}
        <div className="absolute inset-0 w-full h-full overflow-hidden z-10 pointer-events-none">
          {overlays.map(item => (
            <div key={item.id} className="pointer-events-auto">
              <OverlayElement
                item={item}
                isSelected={selectedId === item.id}
                onSelect={setSelectedId}
                onUpdate={handleUpdateOverlay}
                onDelete={handleDeleteOverlay}
                onEdit={handleEditOverlay}
                onLayerAction={handleLayerAction}
                scale={1}
              />
            </div>
          ))}
        </div>
      </div>

      {/* Footer Info */}
      {showUI && (
        <div className="h-6 bg-slate-950 text-slate-500 text-xs flex items-center px-4 justify-between border-t border-slate-800 z-50">
          <span>{overlays.length} item(s)</span>
          <span>
            {background.type === ContentType.YOUTUBE 
              ? 'YouTube Background Active' 
              : background.src 
                ? 'Background Active' 
                : 'No Background'}
          </span>
        </div>
      )}

      {/* URL Input Modal */}
      {modalConfig && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <form 
            onSubmit={handleModalSubmit}
            className="bg-slate-800 border border-slate-700 p-6 rounded-xl shadow-2xl w-full max-w-md transform transition-all scale-100"
          >
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-white">{modalConfig.title}</h3>
              <button 
                type="button" 
                onClick={() => setModalConfig(null)}
                className="text-slate-400 hover:text-white transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            <div className="mb-6">
              <label className="block text-sm font-medium text-slate-400 mb-2">URL / Source</label>
              <input 
                autoFocus
                type="text" 
                placeholder="https://example.com" 
                className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent placeholder-slate-600 transition-all"
                value={urlInput}
                onChange={e => setUrlInput(e.target.value)}
              />
              <p className="text-xs text-slate-500 mt-2">Make sure the site allows iframe embedding.</p>
            </div>

            <div className="flex justify-end gap-3">
              <button 
                type="button" 
                onClick={() => setModalConfig(null)} 
                className="px-4 py-2 text-slate-300 hover:text-white hover:bg-slate-700 rounded-lg transition-colors font-medium"
              >
                Cancel
              </button>
              <button 
                type="submit" 
                className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition-colors font-bold shadow-lg shadow-blue-900/20"
              >
                {modalConfig.defaultValue ? 'Update' : 'Add'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Configuration JSON Modal */}
      {configModalOpen && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
           <div className="bg-slate-800 border border-slate-700 p-6 rounded-xl shadow-2xl w-full max-w-2xl flex flex-col max-h-[90vh]">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-white flex items-center gap-2">
                   Configuration JSON
                </h3>
                <button 
                  onClick={() => setConfigModalOpen(false)}
                  className="text-slate-400 hover:text-white transition-colors"
                >
                  <X size={20} />
                </button>
              </div>

              <div className="flex-1 min-h-0 mb-4">
                <textarea 
                  value={configJson}
                  onChange={(e) => setConfigJson(e.target.value)}
                  className="w-full h-full min-h-[300px] bg-slate-950 font-mono text-xs text-slate-300 p-4 rounded-lg border border-slate-700 focus:outline-none focus:border-blue-500 resize-none"
                  spellCheck={false}
                />
              </div>

              <div className="flex justify-between items-center gap-4">
                 <button 
                   onClick={handleCopyConfig}
                   className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors ${copyFeedback ? 'bg-green-600 text-white' : 'bg-slate-700 text-slate-200 hover:bg-slate-600'}`}
                 >
                   {copyFeedback ? <Check size={18} /> : <Clipboard size={18} />}
                   {copyFeedback ? 'Copied!' : 'Copy to Clipboard'}
                 </button>

                 <div className="flex gap-3">
                   <button 
                     onClick={() => setConfigModalOpen(false)}
                     className="px-4 py-2 text-slate-300 hover:text-white hover:bg-slate-700 rounded-lg transition-colors font-medium"
                   >
                     Cancel
                   </button>
                   <button 
                     onClick={handleApplyConfig}
                     className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition-colors font-bold shadow-lg shadow-blue-900/20"
                   >
                     Apply Configuration
                   </button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { OverlayItem, ContentType } from '../types';
import { Trash2, Pencil, ArrowUpToLine, ArrowDownToLine, ArrowUp, ArrowDown, Timer } from 'lucide-react';
import { getYouTubeEmbedUrl } from '../utils/helpers';

interface OverlayElementProps {
  item: OverlayItem;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onUpdate: (id: string, updates: Partial<OverlayItem>) => void;
  onEdit: (id: string, currentSrc: string) => void;
  onDelete: (id: string) => void;
  onLayerAction: (id: string, action: 'front' | 'back' | 'forward' | 'backward') => void;
  scale: number;
}

export const OverlayElement: React.FC<OverlayElementProps> = ({
  item,
  isSelected,
  onSelect,
  onUpdate,
  onEdit,
  onDelete,
  onLayerAction,
  scale = 1
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [resizeDir, setResizeDir] = useState<string | null>(null);
  const [refreshKey, setRefreshKey] = useState(0);

  const elementRef = useRef<HTMLDivElement>(null);
  const startPos = useRef({ x: 0, y: 0 });
  const startDims = useRef({ x: 0, y: 0, w: 0, h: 0 });

  // Handle Refresh Timer
  useEffect(() => {
    if (item.refreshInterval && item.refreshInterval > 0) {
      const intervalId = setInterval(() => {
        setRefreshKey(prev => prev + 1);
      }, item.refreshInterval * 1000);
      return () => clearInterval(intervalId);
    }
  }, [item.refreshInterval]);

  const handleMouseDown = (e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(item.id);

    if (e.button !== 0) return;

    setIsDragging(true);
    startPos.current = { x: e.clientX, y: e.clientY };
    startDims.current = { x: item.x, y: item.y, w: item.width, h: item.height };

    document.body.classList.add('dragging-active');
  };

  const handleResizeStart = (e: React.MouseEvent, dir: string) => {
    e.stopPropagation();
    e.preventDefault();
    onSelect(item.id);

    setIsResizing(true);
    setResizeDir(dir);
    startPos.current = { x: e.clientX, y: e.clientY };
    startDims.current = { x: item.x, y: item.y, w: item.width, h: item.height };

    document.body.classList.add('dragging-active');
  };

  const onWindowMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging && !isResizing) return;

    const dx = (e.clientX - startPos.current.x) / scale;
    const dy = (e.clientY - startPos.current.y) / scale;

    if (isDragging) {
      onUpdate(item.id, {
        x: startDims.current.x + dx,
        y: startDims.current.y + dy
      });
    } else if (isResizing && resizeDir) {
      let newX = startDims.current.x;
      let newY = startDims.current.y;
      let newW = startDims.current.w;
      let newH = startDims.current.h;

      if (resizeDir.includes('e')) newW = Math.max(50, startDims.current.w + dx);
      if (resizeDir.includes('s')) newH = Math.max(50, startDims.current.h + dy);
      if (resizeDir.includes('w')) {
        const proposedW = startDims.current.w - dx;
        if (proposedW > 50) {
          newX = startDims.current.x + dx;
          newW = proposedW;
        }
      }
      if (resizeDir.includes('n')) {
        const proposedH = startDims.current.h - dy;
        if (proposedH > 50) {
          newY = startDims.current.y + dy;
          newH = proposedH;
        }
      }

      onUpdate(item.id, { x: newX, y: newY, width: newW, height: newH });
    }
  }, [isDragging, isResizing, resizeDir, item.id, onUpdate, scale]);

  const onWindowMouseUp = useCallback(() => {
    if (isDragging || isResizing) {
      setIsDragging(false);
      setIsResizing(false);
      setResizeDir(null);
      document.body.classList.remove('dragging-active');
    }
  }, [isDragging, isResizing]);

  useEffect(() => {
    if (isDragging || isResizing) {
      window.addEventListener('mousemove', onWindowMouseMove);
      window.addEventListener('mouseup', onWindowMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', onWindowMouseMove);
      window.removeEventListener('mouseup', onWindowMouseUp);
    };
  }, [isDragging, isResizing, onWindowMouseMove, onWindowMouseUp]);

  const borderClass = isSelected ? 'border-2 border-blue-500 shadow-[0_0_0_2px_rgba(59,130,246,0.5)]' : 'border border-transparent hover:border-slate-500/50';

  return (
    <div
      ref={elementRef}
      className={`absolute select-none group ${borderClass} transition-shadow duration-150`}
      style={{
        transform: `translate(${item.x}px, ${item.y}px)`,
        width: item.width,
        height: item.height,
        zIndex: item.zIndex,
      }}
      onMouseDown={handleMouseDown}
    >
      {/* Content */}
      <div className="w-full h-full overflow-hidden bg-slate-800/50 relative">
        {item.type === ContentType.IMAGE ? (
          <div
            key={`${item.id}-${refreshKey}`}
            className="w-full h-full bg-cover bg-center bg-no-repeat pointer-events-none"
            style={{ 
              backgroundImage: `url("${item.src}")`, 
              opacity: item.opacity 
            }}
          />
        ) : item.type === ContentType.YOUTUBE ? (
          <>
            <div className="absolute inset-0 z-10 bg-transparent" />
            <iframe 
              key={`${item.id}-${refreshKey}`}
              src={getYouTubeEmbedUrl(item.src)}
              className="w-full h-full pointer-events-none" 
              title={`frame-${item.id}`}
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
              referrerPolicy="strict-origin-when-cross-origin"
              style={{ opacity: item.opacity }}
            />
          </>
        ) : (
          <>
            <div className="absolute inset-0 z-10 bg-transparent" />
            <iframe 
              key={`${item.id}-${refreshKey}`}
              src={item.src} 
              className="w-full h-full pointer-events-none" 
              title={`frame-${item.id}`}
              style={{ opacity: item.opacity }}
            />
          </>
        )}
      </div>

      {/* Controls Overlay (Visible on Select) */}
      {(isSelected) && (
        <>
          {/* Edge Resize Handles */}
          <div className="absolute -top-1 left-2 right-2 h-2 cursor-n-resize z-40" onMouseDown={(e) => handleResizeStart(e, 'n')} />
          <div className="absolute -bottom-1 left-2 right-2 h-2 cursor-s-resize z-40" onMouseDown={(e) => handleResizeStart(e, 's')} />
          <div className="absolute top-2 bottom-2 -left-1 w-2 cursor-w-resize z-40" onMouseDown={(e) => handleResizeStart(e, 'w')} />
          <div className="absolute top-2 bottom-2 -right-1 w-2 cursor-e-resize z-40" onMouseDown={(e) => handleResizeStart(e, 'e')} />

          {/* Corner Resize Handles */}
          <div className="absolute -top-1.5 -left-1.5 w-3 h-3 bg-blue-500 cursor-nw-resize rounded-full border border-white z-50" onMouseDown={(e) => handleResizeStart(e, 'nw')} />
          <div className="absolute -top-1.5 -right-1.5 w-3 h-3 bg-blue-500 cursor-ne-resize rounded-full border border-white z-50" onMouseDown={(e) => handleResizeStart(e, 'ne')} />
          <div className="absolute -bottom-1.5 -left-1.5 w-3 h-3 bg-blue-500 cursor-sw-resize rounded-full border border-white z-50" onMouseDown={(e) => handleResizeStart(e, 'sw')} />
          <div className="absolute -bottom-1.5 -right-1.5 w-3 h-3 bg-blue-500 cursor-se-resize rounded-full border border-white z-50" onMouseDown={(e) => handleResizeStart(e, 'se')} />

          {/* Top Right Controls: Delete & Edit */}
          <div className="absolute -top-10 right-0 flex items-center gap-1 z-50">
             <button
              className="bg-slate-700 text-slate-200 p-1.5 rounded-md shadow-sm hover:bg-slate-600 transition-colors"
              onMouseDown={(e) => { e.stopPropagation(); onEdit(item.id, item.src); }}
              title="Edit Source"
            >
              <Pencil size={16} />
            </button>
            <button
              className="bg-red-500 text-white p-1.5 rounded-md shadow-sm hover:bg-red-600 transition-colors"
              onMouseDown={(e) => { e.stopPropagation(); onDelete(item.id); }}
              title="Remove Overlay"
            >
              <Trash2 size={16} />
            </button>
          </div>

          {/* Top Left Controls: Layer Ordering */}
          <div className="absolute -top-10 left-0 flex items-center gap-1 z-50 bg-slate-800 p-1 rounded-md border border-slate-700 shadow-sm">
            <button
              className="text-slate-300 hover:text-white hover:bg-slate-700 p-1 rounded"
              onMouseDown={(e) => { e.stopPropagation(); onLayerAction(item.id, 'front'); }}
              title="Bring to Front"
            >
              <ArrowUpToLine size={14} />
            </button>
            <button
              className="text-slate-300 hover:text-white hover:bg-slate-700 p-1 rounded"
              onMouseDown={(e) => { e.stopPropagation(); onLayerAction(item.id, 'forward'); }}
              title="Bring Forward"
            >
              <ArrowUp size={14} />
            </button>
             <button
              className="text-slate-300 hover:text-white hover:bg-slate-700 p-1 rounded"
              onMouseDown={(e) => { e.stopPropagation(); onLayerAction(item.id, 'backward'); }}
              title="Send Backward"
            >
              <ArrowDown size={14} />
            </button>
            <button
              className="text-slate-300 hover:text-white hover:bg-slate-700 p-1 rounded"
              onMouseDown={(e) => { e.stopPropagation(); onLayerAction(item.id, 'back'); }}
              title="Send to Back"
            >
              <ArrowDownToLine size={14} />
            </button>
          </div>

          {/* Opacity & Refresh Control */}
          <div className="absolute -top-10 right-20 bg-slate-800 p-1 rounded-md shadow-sm flex items-center gap-2 border border-slate-700 z-50" onMouseDown={e => e.stopPropagation()}>
             {/* Refresh Timer Input */}
             <div className="flex items-center gap-1 pl-1 border-r border-slate-600 pr-2 mr-1" title="Auto-refresh interval in seconds (0 to disable)">
               <Timer size={14} className={item.refreshInterval ? "text-blue-400" : "text-slate-500"} />
               <input 
                 type="number" 
                 min="0"
                 placeholder="Off"
                 value={item.refreshInterval || ''}
                 onChange={(e) => {
                   const val = parseInt(e.target.value);
                   onUpdate(item.id, { refreshInterval: isNaN(val) ? 0 : val });
                 }}
                 className="w-10 bg-transparent text-xs text-white focus:outline-none text-center appearance-none"
               />
               <span className="text-[10px] text-slate-500">s</span>
             </div>

             <span className="text-xs text-slate-400 px-1">Opacity</span>
             <input 
               type="range" 
               min="0.1" 
               max="1" 
               step="0.1" 
               value={item.opacity} 
               onChange={(e) => onUpdate(item.id, { opacity: parseFloat(e.target.value) })}
               className="w-16 h-1 bg-slate-600 rounded-lg appearance-none cursor-pointer"
             />
          </div>
        </>
      )}
    </div>
  );
};

import React, { useRef } from 'react';
import { Download, Upload, Plus, Image as ImageIcon, Globe, Monitor, Settings, Trash, EyeOff, Maximize, Minimize, Link, FileJson, Bookmark } from 'lucide-react';
import { fileToDataUri } from '../utils/helpers';
import { ContentType, OverlayItem } from '../types';

interface ToolbarProps {
  currentBackground: { type: ContentType, src: string };
  onAddOverlay: (type: ContentType, src: string) => void;
  onSetBackground: (type: ContentType, src: string) => void;
  onSave: () => void;
  onLoad: (file: File) => void;
  onClear: () => void;
  onOpenUrlModal: (title: string, callback: (src: string) => void, defaultValue?: string) => void;
  onOpenConfigModal: () => void;
  onHideUI: () => void;
  onToggleFullScreen: () => void;
  onBookmark: () => void;
  isFullScreen: boolean;
}

const BTN_PRIMARY = "flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-slate-100 px-3 py-2 rounded-md transition-all active:scale-95 border border-slate-600 cursor-pointer";
const BTN_SECONDARY = "flex items-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-300 px-3 py-2 rounded-md transition-all active:scale-95 border border-slate-700 cursor-pointer";

export const Toolbar: React.FC<ToolbarProps> = ({
  currentBackground,
  onAddOverlay,
  onSetBackground,
  onSave,
  onLoad,
  onClear,
  onOpenUrlModal,
  onOpenConfigModal,
  onHideUI,
  onToggleFullScreen,
  onBookmark,
  isFullScreen
}) => {
  const bgInputRef = useRef<HTMLInputElement>(null);
  const overlayInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  const handleBgUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const uri = await fileToDataUri(e.target.files[0]);
      onSetBackground(ContentType.IMAGE, uri);
    }
    // Reset
    if (bgInputRef.current) bgInputRef.current.value = '';
  };

  const handleOverlayUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const uri = await fileToDataUri(e.target.files[i]);
        onAddOverlay(ContentType.IMAGE, uri);
      }
    }
    if (overlayInputRef.current) overlayInputRef.current.value = '';
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      onLoad(e.target.files[0]);
    }
    if (importInputRef.current) importInputRef.current.value = '';
  };

  const getBackgroundUrlDefault = () => {
    if (currentBackground.type === ContentType.YOUTUBE) {
      return `https://www.youtube.com/watch?v=${currentBackground.src}`;
    }
    if (currentBackground.type === ContentType.IFRAME || currentBackground.type === ContentType.IMAGE) {
      // Don't pre-fill if it's a massive data URI
      if (currentBackground.src.startsWith('data:')) return '';
      return currentBackground.src;
    }
    return '';
  };

  return (
    <div className="h-16 bg-slate-800 border-b border-slate-700 flex items-center px-4 justify-between select-none shadow-md z-50 relative">
      <div className="flex items-center gap-4">
        <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2">
          <Settings className="text-blue-400" /> Layout Forge
        </h1>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        {/* Background Controls */}
        <div className="flex items-center gap-2">
          <span className="text-xs uppercase font-semibold text-slate-500 tracking-wider">Background</span>
          <button 
            onClick={() => bgInputRef.current?.click()}
            className={BTN_SECONDARY}
            title="Set Background Image"
          >
            <ImageIcon size={18} />
          </button>
          <button 
            onClick={() => onOpenUrlModal(
              "Set Background Web Page", 
              (url) => onSetBackground(ContentType.IFRAME, url),
              getBackgroundUrlDefault()
            )}
            className={BTN_SECONDARY}
            title="Set Background URL"
          >
            <Globe size={18} />
          </button>
          <input ref={bgInputRef} type="file" accept="image/*" className="hidden" onChange={handleBgUpload} />
        </div>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        {/* Overlay Controls */}
        <div className="flex items-center gap-2">
          <span className="text-xs uppercase font-semibold text-slate-500 tracking-wider">Overlays</span>
          <button 
            onClick={() => overlayInputRef.current?.click()}
            className={BTN_PRIMARY}
            title="Add Image Overlay"
          >
            <Plus size={18} /> <ImageIcon size={18} />
          </button>
          <button 
            onClick={() => onOpenUrlModal("Add Web Image Overlay", (url) => onAddOverlay(ContentType.IMAGE, url))}
            className={BTN_PRIMARY}
            title="Add Web Image Overlay"
          >
             <Plus size={18} /> <Link size={18} />
          </button>
          <button 
            onClick={() => onOpenUrlModal("Add Web Page Overlay", (url) => onAddOverlay(ContentType.IFRAME, url))}
            className={BTN_PRIMARY}
            title="Add Website Overlay"
          >
            <Plus size={18} /> <Monitor size={18} />
          </button>
          <input ref={overlayInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleOverlayUpload} />
        </div>
      </div>

      <div className="flex items-center gap-3">
        <button 
          onClick={onToggleFullScreen}
          className="text-slate-400 hover:text-white hover:bg-slate-700/50 p-2 rounded-md transition-colors flex items-center gap-2"
          title="Toggle Full Screen"
        >
          {isFullScreen ? <Minimize size={18} /> : <Maximize size={18} />}
        </button>
        <button 
          onClick={onHideUI}
          className="text-slate-400 hover:text-white hover:bg-slate-700/50 p-2 rounded-md transition-colors flex items-center gap-2"
          title="Hide Toolbar & Status"
        >
          <EyeOff size={18} />
        </button>

        <div className="h-8 w-px bg-slate-600 mx-2"></div>

        <button 
          onClick={onClear}
          className="text-red-400 hover:text-red-300 hover:bg-red-900/20 px-3 py-2 rounded-md transition-colors flex items-center gap-2 cursor-pointer"
        >
          <Trash size={16} /> <span className="hidden sm:inline">Clear</span>
        </button>

        <button 
          onClick={() => importInputRef.current?.click()}
          className="text-slate-300 hover:text-white hover:bg-slate-700 px-3 py-2 rounded-md transition-colors flex items-center gap-2 cursor-pointer"
        >
          <Upload size={16} /> <span className="hidden sm:inline">Import</span>
        </button>
        <input ref={importInputRef} type="file" accept=".json" className="hidden" onChange={handleImport} />

        <button 
          onClick={onSave}
          className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-md transition-colors shadow-lg flex items-center gap-2 font-medium cursor-pointer"
        >
          <Download size={16} /> Export
        </button>

        <button 
          onClick={onOpenConfigModal}
          className="text-slate-300 hover:text-white hover:bg-slate-700 px-3 py-2 rounded-md transition-colors flex items-center gap-2 cursor-pointer"
          title="View/Edit Configuration JSON"
        >
          <FileJson size={16} />
        </button>

         <button 
          onClick={onBookmark}
          className="text-slate-300 hover:text-white hover:bg-slate-700 px-3 py-2 rounded-md transition-colors flex items-center gap-2 cursor-pointer"
          title="Update URL to Bookmark Configuration"
        >
          <Bookmark size={16} />
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Toolbar } from './components/Toolbar';
import { OverlayElement } from './components/OverlayElement';
import { OverlayItem, AppState, ContentType, DEFAULT_WIDTH, DEFAULT_HEIGHT } from './types';
import { generateId, downloadJson, getYouTubeId, getYouTubeEmbedUrl, isImageUrl } from './utils/helpers';
import { Eye, X, Maximize, Minimize, Clipboard, Check } from 'lucide-react';

// Helper to check for existing saved state
const STORAGE_KEY = 'layout_forge_state';

const App: React.FC = () => {
  const [background, setBackground] = useState<{ type: ContentType, src: string }>({
    type: ContentType.IMAGE,
    src: ''
  });
  const [overlays, setOverlays] = useState<OverlayItem[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [showUI, setShowUI] = useState(true);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Modal State
  const [modalConfig, setModalConfig] = useState<{
    isOpen: boolean;
    title: string;
    defaultValue?: string;
    callback: (url: string) => void;
  } | null>(null);
  const [urlInput, setUrlInput] = useState('');

  // Config JSON Modal
  const [configModalOpen, setConfigModalOpen] = useState(false);
  const [configJson, setConfigJson] = useState('');
  const [copyFeedback, setCopyFeedback] = useState(false);

  // --- Persistence & Initialization ---

  // Load from URL or local storage on mount
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const configParam = params.get('config');

    if (configParam) {
      try {
        const parsed: AppState = JSON.parse(decodeURIComponent(configParam));
        if (parsed) {
          setBackground({ 
            type: parsed.backgroundType || ContentType.IMAGE, 
            src: parsed.backgroundSrc || '' 
          });
          setOverlays(parsed.overlays || []);
          // Note: We deliberately do NOT remove the param here so the user can see it works,
          // though we might want to if we want a clean URL. For bookmarking purposes, keeping it is helpful?
          // Actually, if we bookmark, we want it there. If we just load, we might want to clean it up?
          // Let's leave it.
          return;
        }
      } catch (e) {
        console.error("Failed to parse config from URL", e);
      }
    }

    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed: AppState = JSON.parse(saved);
        setBackground({ type: parsed.backgroundType, src: parsed.backgroundSrc });
        setOverlays(parsed.overlays);
      } catch (e) {
        console.error("Failed to load state", e);
      }
    }
  }, []);

  // Save to local storage whenever state changes
  useEffect(() => {
    const state: AppState = {
      backgroundType: background.type,
      backgroundSrc: background.src,
      overlays
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [background, overlays]);

  // Handle Full Screen Change Events
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  // --- Actions ---

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  const handleAddOverlay = (type: ContentType, src: string) => {
    let finalType = type;
    let finalSrc = src;

    // Check if the source is actually a YouTube link
    const ytId = getYouTubeId(src);
    if (ytId) {
      finalType = ContentType.YOUTUBE;
      finalSrc = ytId;
    } else if (isImageUrl(src)) {
      // Auto-detect image
      finalType = ContentType.IMAGE;
    }

    // Determine reasonable default dimensions based on content type
    const width = finalType === ContentType.IMAGE ? DEFAULT_WIDTH : 600;
    const height = finalType === ContentType.IMAGE ? DEFAULT_HEIGHT : 450;

    // Calculate max z-index
    const maxZ = overlays.length > 0 ? Math.max(...overlays.map(o => o.zIndex)) : 0;

    const newOverlay: OverlayItem = {
      id: generateId(),
      type: finalType,
      src: finalSrc,
      x: 100 + (overlays.length * 20), // Cascade effect
      y: 100 + (overlays.length * 20),
      width,
      height,
      zIndex: maxZ + 1,
      opacity: 1,
    };
    setOverlays(prev => [...prev, newOverlay]);
    setSelectedId(newOverlay.id);
  };

  const handleSetBackground = (type: ContentType, src: string) => {
    // Check for YouTube URL
    const ytId = getYouTubeId(src);
    if (ytId) {
      setBackground({ type: ContentType.YOUTUBE, src: ytId });
    } else if (isImageUrl(src)) {
      setBackground({ type: ContentType.IMAGE, src });
    } else {
      setBackground({ type, src });
    }
  };

  const handleUpdateOverlay = useCallback((id: string, updates: Partial<OverlayItem>) => {
    setOverlays(prev => prev.map(item => 
      item.id === id ? { ...item, ...updates } : item
    ));
  }, []);

  const handleDeleteOverlay = (id: string) => {
    setOverlays(prev => prev.filter(item => item.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const handleEditOverlay = (id: string, currentSrc: string) => {
    const item = overlays.find(o => o.id === id);
    const title = item?.type === ContentType.IMAGE ? "Edit Image Source" : "Edit URL";

    // For YouTube items, reconstruct a watch URL for editing if possible, or just pass the ID
    let displayValue = currentSrc;
    if (item?.type === ContentType.YOUTUBE) {
        displayValue = `https://www.youtube.com/watch?v=${currentSrc}`;
    }

    openUrlModal(title, (newUrl) => {
       // Check if new URL is YouTube
       const ytId = getYouTubeId(newUrl);
       if (ytId) {
         handleUpdateOverlay(id, { type: ContentType.YOUTUBE, src: ytId });
       } else if (isImageUrl(newUrl)) {
         handleUpdateOverlay(id, { type: ContentType.IMAGE, src: newUrl });
       } else {
         handleUpdateOverlay(id, { src: newUrl });
       }
    }, displayValue);
  };

  // Reorder Logic
  const handleLayerAction = (id: string, action: 'front' | 'back' | 'forward' | 'backward') => {
    setOverlays(prev => {
      // 1. Create a copy and sort by current zIndex to establish order
      const items = [...prev].sort((a, b) => a.zIndex - b.zIndex);

      const idx = items.findIndex(i => i.id === id);
      if (idx === -1) return prev;

      const item = items[idx];
      items.splice(idx, 1); // Remove item from current position

      // 2. Insert at new position
      if (action === 'front') {
        items.push(item);
      } else if (action === 'back') {
        items.unshift(item);
      } else if (action === 'forward') {
        // Swap with next if possible
        const newIdx = Math.min(items.length, idx + 1);
        items.splice(newIdx, 0, item);
      } else if (action === 'backward') {
        // Swap with prev if possible
        const newIdx = Math.max(0, idx - 1);
        items.splice(newIdx, 0, item);
      }

      // 3. Re-assign zIndices sequentially to normalize
      return items.map((itm, index) => ({
        ...itm,
        zIndex: index + 1
      }));
    });
