          onSetBackground={handleSetBackground}
          onSave={handleExport}
          onLoad={handleImport}
          onClear={handleClear}
          onOpenUrlModal={openUrlModal}
          onOpenConfigModal={handleOpenConfig}
          onHideUI={() => setShowUI(false)}
          onToggleFullScreen={toggleFullScreen}
          onBookmark={handleBookmark}
