  onEdit: (id: string, currentSrc: string) => void;
  onDelete: (id: string) => void;
  onLayerAction: (id: string, action: 'front' | 'back' | 'forward' | 'backward') => void;
  scale: number;
}

export const OverlayElement: React.FC<OverlayElementProps> = ({
  item,
  isSelected,
  onSelect,
  onUpdate,
  onEdit,
  onDelete,
  onLayerAction,
  scale = 1
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [resizeDir, setResizeDir] = useState<string | null>(null);

  // Use a timestamp for cache-busting instead of a simple counter
  const [refreshTimestamp, setRefreshTimestamp] = useState<number>(0);

  const elementRef = useRef<HTMLDivElement>(null);
  const startPos = useRef({ x: 0, y: 0 });
  const startDims = useRef({ x: 0, y: 0, w: 0, h: 0 });

  // Handle Refresh Timer
  useEffect(() => {
    if (!item.refreshInterval || item.refreshInterval <= 0) {
      // If we are not in a retry loop (triggered by error), reset timestamp
      // However, if we preserve this, it might conflict with manual error retries.
      // Let's rely on the interval. If user manually sets interval, this runs.
      // If not, refreshTimestamp stays 0 unless error logic sets it.
      if (refreshTimestamp === 0) return; 

      // If we have a timestamp but interval is off, it might be due to error retry.
      // We generally leave it unless we want to "reset" when interval is turned off.
      // For now, let's keep it simple: this effect manages periodic refresh.
      return;
    }

    const intervalId = setInterval(() => {
      setRefreshTimestamp(Date.now());
    }, item.refreshInterval * 1000);
    return () => clearInterval(intervalId);
  }, [item.refreshInterval]);

  const handleMouseDown = (e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(item.id);

    if (e.button !== 0) return;

    setIsDragging(true);
    startPos.current = { x: e.clientX, y: e.clientY };
    startDims.current = { x: item.x, y: item.y, w: item.width, h: item.height };

    document.body.classList.add('dragging-active');
  };

  const handleResizeStart = (e: React.MouseEvent, dir: string) => {
    e.stopPropagation();
    e.preventDefault();
    onSelect(item.id);

    setIsResizing(true);
    setResizeDir(dir);
    startPos.current = { x: e.clientX, y: e.clientY };
    startDims.current = { x: item.x, y: item.y, w: item.width, h: item.height };

    document.body.classList.add('dragging-active');
  };

  const onWindowMouseMove = useCallback((e: MouseEvent) => {
    if (!isDragging && !isResizing) return;

    const dx = (e.clientX - startPos.current.x) / scale;
