      document.body.classList.remove('dragging-active');
    }
  }, [isDragging, isResizing]);

  useEffect(() => {
    if (isDragging || isResizing) {
      window.addEventListener('mousemove', onWindowMouseMove);
      window.addEventListener('mouseup', onWindowMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', onWindowMouseMove);
      window.removeEventListener('mouseup', onWindowMouseUp);
    };
  }, [isDragging, isResizing, onWindowMouseMove, onWindowMouseUp]);

  const borderClass = isSelected ? 'border-2 border-blue-500 shadow-[0_0_0_2px_rgba(59,130,246,0.5)]' : 'border border-transparent hover:border-slate-500/50';

  // Helper to generate the display URL with cache busting if needed
  const getDisplayUrl = () => {
    if (item.type === ContentType.YOUTUBE) {
       return getYouTubeEmbedUrl(item.src);
    }

    // For images and generic iframes, append timestamp if active
    if (refreshTimestamp > 0 && !item.src.startsWith('data:')) {
        const separator = item.src.includes('?') ? '&' : '?';
        return `${item.src}${separator}t=${refreshTimestamp}`;
    }
    return item.src;
  };

  const handleImageError = () => {
    if (item.src.startsWith('data:')) return; // Don't retry data URIs

    // Retry logic: wait 1 second then update timestamp to force reload
    setTimeout(() => {
      setRefreshTimestamp(Date.now());
    }, 1000);
  };

  const displayUrl = getDisplayUrl();
  const contentKey = `${item.id}-${refreshTimestamp}`;

  return (
    <div
      ref={elementRef}
      className={`absolute select-none group ${borderClass} transition-shadow duration-150 pointer-events-auto`}
      style={{
        transform: `translate(${item.x}px, ${item.y}px)`,
        width: item.width,
        height: item.height,
        zIndex: item.zIndex,
      }}
      onMouseDown={handleMouseDown}
    >
      {/* Content */}
      <div className="w-full h-full overflow-hidden bg-slate-800/50 relative">
        {item.type === ContentType.IMAGE ? (
          <img
            key={contentKey}
            src={displayUrl}
            alt="Overlay"
            className="w-full h-full object-cover object-center pointer-events-none select-none block"
            style={{ opacity: item.opacity }}
            onError={handleImageError}
          />
        ) : item.type === ContentType.YOUTUBE ? (
          <>
            <div className="absolute inset-0 z-10 bg-transparent" />
            <iframe 
              key={contentKey}
              src={displayUrl}
              className="w-full h-full pointer-events-none" 
              title={`frame-${item.id}`}
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
              referrerPolicy="strict-origin-when-cross-origin"
              style={{ opacity: item.opacity }}
            />
          </>
        ) : (
          <>
            <div className="absolute inset-0 z-10 bg-transparent" />
            <iframe 
              key={contentKey}
              src={displayUrl} 
              className="w-full h-full pointer-events-none" 
              title={`frame-${item.id}`}
              style={{ opacity: item.opacity }}
              referrerPolicy="no-referrer"
            />
          </>
        )}
      </div>

      {/* Controls Overlay (Visible on Select) */}
      {(isSelected) && (
        <>
          {/* Edge Resize Handles */}
          <div className="absolute -top-1 left-2 right-2 h-2 cursor-n-resize z-40" onMouseDown={(e) => handleResizeStart(e, 'n')} />
          <div className="absolute -bottom-1 left-2 right-2 h-2 cursor-s-resize z-40" onMouseDown={(e) => handleResizeStart(e, 's')} />
